// Match video to tenant's issue using category + keyword relevance
const output = $('Format Output').item.json;
const videos = $('Search Video').all().map(v => v.json);
const message = (output.message || '').toLowerCase();
const history = ($('Format Context').item.json.history_text || '').toLowerCase();
const fullContext = message + ' ' + history;

// Get classified category from Classify Action
let classifiedCategory = '';
try {
  const classifyRaw = $('Classify Action').item.json.output || $('Classify Action').item.json.text || '';
  const classifyJson = JSON.parse(classifyRaw.replace(/```json/g, '').replace(/```/g, '').trim());
  classifiedCategory = (classifyJson.category || '').toLowerCase();
} catch(e) {}

// Get ticket_id from Generate Ticket if a new ticket was created/upgraded.
// On pure-continuation messages, Generate Ticket doesn't run — fall back to
// the most recent open ticket for this tenant so the dedup chain (video,
// Phase A) still has a ticket_id to work with.
let ticketId = '';
try { ticketId = $('Generate Ticket').item.json.ticket_id || ''; } catch(e) {}
if (!ticketId) {
  try {
    const open = $('Get Open Tickets').all().map(t => t.json);
    const fresh = open.find(t => t.ticket_id && !['resolved', 'closed'].includes((t.status || '').toLowerCase()));
    if (fresh) ticketId = fresh.ticket_id;
  } catch(e) {}
}

// Categories that have no repair videos — never suggest videos for these
const noVideoCategories = ['parking', 'lease_admin', 'general_inquiry', 'pest_control', 'none', ''];

if (noVideoCategories.includes(classifiedCategory)) {
  return [{
    json: {
      ...output,
      response_text: output.response_text || '',
      has_video: false,
      video_url: '',
      video_title: '',
      ticket_id: ticketId
    }
  }];
}

let bestVideo = null;
let bestScore = 0;

for (const video of videos) {
  const videoCategory = (video.category || '').toLowerCase();
  const keywords = (video.keywords || '').replace(/[{}"]/g, '').split(',');
  let score = 0;

  for (const kw of keywords) {
    const words = kw.trim().toLowerCase().split(' ');
    const allMatch = words.every(w => w.length > 2 && fullContext.includes(w));
    if (allMatch) score += words.length;
  }

  // Boost score if video category matches classified category
  if (classifiedCategory && videoCategory === classifiedCategory) {
    score *= 2;
  }
  // Penalize if categories don't match at all
  else if (classifiedCategory && videoCategory !== classifiedCategory && videoCategory !== 'general') {
    score = Math.floor(score * 0.3);
  }

  if (score > bestScore) {
    bestScore = score;
    bestVideo = video;
  }
}

let responseText = output.response_text || '';
// Require higher threshold: score >= 4 (was 2)
const hasVideo = bestVideo && bestScore >= 4;

if (hasVideo) {
  const isFrench = responseText.includes('Bonjour') || responseText.includes('merci') || responseText.includes('votre');
  responseText += '\n\n---\n';
  if (isFrench) {
    responseText += 'Cette vidéo pourrait vous aider : ' + bestVideo.title + '\n' + bestVideo.video_url;
  } else {
    responseText += 'This video might help: ' + bestVideo.title + '\n' + bestVideo.video_url;
  }
}

return [{
  json: {
    ...output,
    response_text: responseText,
    has_video: hasVideo,
    video_url: bestVideo?.video_url || '',
    video_title: bestVideo?.title || '',
    ticket_id: ticketId
  }
}];

const ownerChatId = $('Get Owner Chat ID').first().json.owner_chat_id;
const ticket = $('Generate Ticket').item.json;
const isUrgent = ticket.urgency === 'urgent';
const botToken = $env.TELEGRAM_BOT_TOKEN || 'TELEGRAM_BOT_TOKEN_SET_IN_ENV';
// Is Dion testing? Route to Dion instead of Julia
const tenantPhone = $('Generate Ticket').item.json.phone || '';
const isDion = tenantPhone.includes('5148319058');
const chatId = isDion ? '6216258938' : ownerChatId;


let text = '';
let replyMarkup = null;

if (isUrgent) {
  text = '\u{1F6A8} <b>URGENT TICKET ' + ticket.ticket_id + '</b>\n\n'
    + '<b>Category:</b> ' + (ticket.category || '').replace(/_/g, ' ') + '\n'
    + '<b>Tenant:</b> ' + (ticket.tenant_name || '') + '\n'
    + '<b>Unit:</b> ' + (ticket.unit || '') + '\n'
    + '<b>Summary:</b> ' + (ticket.summary || '');
  replyMarkup = JSON.stringify({
    inline_keyboard: [[
      { text: 'Auto Dispatch', callback_data: 'dispatch||' + ticket.ticket_id + '||' + (ticket.category || '') },
      { text: 'Show Contractors', callback_data: 'manual||' + ticket.ticket_id + '||' + (ticket.category || '') }
    ]]
  });
} else {
  text = '\u{1F4CB} <b>NEW TICKET ' + ticket.ticket_id + '</b>\n\n'
    + '<b>Category:</b> ' + (ticket.category || '').replace(/_/g, ' ') + '\n'
    + '<b>Tenant:</b> ' + (ticket.tenant_name || '') + '\n'
    + '<b>Unit:</b> ' + (ticket.unit || '') + '\n'
    + '<b>Summary:</b> ' + (ticket.summary || '');
}

const body = { chat_id: chatId, text, parse_mode: 'HTML' };
if (replyMarkup) body.reply_markup = replyMarkup;

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + botToken + '/sendMessage',
  body,
  json: true
});

return [{ json: { sent: true, ownerChatId: chatId, ticketId: ticket.ticket_id, isUrgent } }];

// Phase A — passive duplicate detection. Uses Haiku to ask "is the just-
// created ticket about the same underlying issue as one of this tenant's
// other OPEN tickets in the same category?" Logs the verdict on the new
// ticket via would_have_merged_with WITHOUT changing the workflow flow.
// On any error returns matched_ticket_id = "none" — never throws.

// Pull ticket data from Create Ticket directly — $input here is Send Owner
// Notification's Telegram API response, which has no ticket fields.
let newTicket = {};
try { newTicket = $('Create Ticket').first().json || {}; } catch(e) { newTicket = {}; }
const newTicketId = newTicket.ticket_id || '';
const newCategory = (newTicket.category || '').toLowerCase();
const newSummary = newTicket.summary || newTicket.tenant_message || '';

if (!newTicketId || !newSummary) {
  return [{ json: { ticket_id: newTicketId, matched_ticket_id: 'none', skipped: 'no_data' } }];
}

let candidates = [];
try {
  const allOpen = $('Get Open Tickets').all().map(t => t.json);
  candidates = allOpen.filter(t =>
    t.ticket_id &&
    t.ticket_id !== newTicketId &&
    (t.category || '').toLowerCase() === newCategory &&
    !['resolved', 'closed'].includes((t.status || '').toLowerCase())
  ).slice(0, 5);
} catch(e) {
  return [{ json: { ticket_id: newTicketId, matched_ticket_id: 'none', error: 'no_open_tickets' } }];
}

if (candidates.length === 0) {
  return [{ json: { ticket_id: newTicketId, matched_ticket_id: 'none', skipped: 'no_candidates' } }];
}

const candidateList = candidates.map((t, i) =>
  (i + 1) + '. ' + t.ticket_id + ': "' + (t.summary || '').replace(/"/g, '\\"') + '"'
).join('\n');

let matched = 'none';
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 32,
      messages: [{
        role: 'user',
        content: 'A new maintenance ticket was just created for a tenant.\n\nNEW TICKET: "' + newSummary.replace(/"/g, '\\"') + '"\n\nThe same tenant has these other OPEN tickets in the same category:\n' + candidateList + '\n\nQUESTION: Is the new ticket the SAME SPECIFIC PROBLEM as one of the existing ones — i.e. a follow-up, escalation, or restatement of the exact same issue (same fixture, same symptom, same location)?\n\nSTRICT MATCHING RULES — answer "none" UNLESS ALL conditions are met:\n  • Same FIXTURE or APPLIANCE (e.g. sink ≠ toilet ≠ dishwasher; light fixture ≠ outlet)\n  • Same ROOM or LOCATION when relevant (e.g. kitchen sink ≠ bathroom sink)\n  • Same TYPE of problem (e.g. leak ≠ clog ≠ low pressure; flickering ≠ no power)\n\nDifferent fixtures or different problems within the same category are SEPARATE TICKETS. Only match if it is clearly the SAME problem continuing or escalating.\n\nReply with ONLY the matching ticket_id (e.g. "TK-ABC12345") if YES.\nReply with ONLY "none" if NO. When in doubt, reply "none".'
      }]
    }),
    returnFullResponse: false,
    timeout: 5000
  });

  const parsed = typeof response === 'string' ? JSON.parse(response) : response;
  const text = (parsed.content?.[0]?.text || '').trim();
  if (text.startsWith('TK-') && candidates.some(c => c.ticket_id === text)) {
    matched = text;
  }
} catch(e) {
  return [{ json: { ticket_id: newTicketId, matched_ticket_id: 'none', error: (e.message || 'haiku_error') } }];
}

return [{ json: { ticket_id: newTicketId, matched_ticket_id: matched } }];
